INSERT INTO `tbl_connection` (`id`, `location_a_id`, `location_b_id`, `weight`, `pmr`, `instruction_a_to_b`, `instruction_b_to_a`) VALUES
	(1, 9, 23, 1, 1, 'passer par la porte qui est à droite quand on regarde vers les portes coulissantes, sur la porte il y a un cadre "secretariat"', 'passer par la porte'),
	(2, 9, 2, 1, 1, 'passer par les portes coulissantes et se sera la partie gauche du couloir', 'quand on arrive devant une heure numérique rouge, on peut voir des portes coulissantes, il faut passer par les portes coulissantes'),
	(3, 2, 6, 1, 0, 'si vous voyez une heure numérique rouge, vous devez voir des escaliers derrière', 'si vous voyez une heure numérique rouge, le couloir est derrière et se sera la partie à votre droite'),
	(4, 6, 10, 1, 0, 'en montant une partie des escaliers, il y a une grande porte avec le cadre "salle du mont"', 'passer par la grande porte'),
	(5, 2, 12, 1, 1, 'la salle S7 a une porte avec un cadre "7", si vous êtes au niveau des portes coulissantes se sera la 2ème porte à votre gauche, si vous êtes dans un carrefour se sera la 5ème porte à votre droite', 'passer par la porte'),
	(6, 2, 13, 1, 1, 'la salle S11 a une porte avec un cadre "11", si vous êtes au niveau des portes coulissantes se sera la 3ème porte à votre gauche, si vous êtes dans un carrefour se sera la 4ème porte à votre droite', 'passer par la porte'),
	(7, 2, 14, 1, 1, 'la salle S15 a une porte avec un cadre "15", si vous êtes au niveau des portes coulissantes se sera la 3ème porte à votre gauche, si vous êtes dans un carrefour se sera la 3ème porte à votre droite', 'passer par la porte'),
	(8, 2, 15, 1, 1, 'la salle S19 a une porte avec un cadre "19", si vous êtes au niveau des portes coulissantes se sera la 4ème porte à votre gauche, si vous êtes dans un carrefour se sera la 2ème porte à votre droite', 'passer par la porte'),
	(9, 2, 16, 1, 1, 'le foyer TV a une porte avec un cadre "foyer TV", si vous êtes au niveau des portes coulissantes se sera la 5ème porte à votre gauche, si vous êtes dans un carrefour se sera la 1ère porte à votre droite', 'passer par la porte'),
	(10, 2, 157, 1, 1, 'aller devant les portes coulissantes au milieu du couloir, en regardant les portes coulissantes aller à votre droite jusqu\'à être à un endroit avec plusieurs chemins', 'regarder autour de vous, le couloir principal est le couloir qui est le plus long'),
	(11, 157, 17, 1, 1, 'regarder vers le couloir principal, retournez-vous et se sera la portre de gauche', 'passer par la porte'),
	(12, 157, 22, 1, 1, 'regarder autour de vous jusqu\'à voir des portes rouges, passer par les portes rouge, vous devrez voir des casiers dans la pièce où vous êtes, les 2 portes mènent à la cantine', 'regarder vers les fenêtres ,tournez-vous vers la droite, il devrai y avoir une porte, passer la, normalement vous êtes dans une pièce avec des casiers, passer dans le passage qui est entre les casiers'),
	(13, 157, 1, 1, 1, 'regarder autour de vous jusqu\'à voir un ascenseur gris', 'quand vous sortez de l\'ascenseur, aller dans le passage qui est en face'),
	(14, 157, 8, 1, 0, 'regarder autour de vous jusqu\'à voir l\'ascenseur, aller vers l\'ascenseur, tourner a gauche et normalement vous devriez voir des escaliers', 'regarder la porte qui mène à la cour, tourner a droite, il devrai y avoir un passage'),
	(15, 2, 20, 1, 1, 'la salle immanuel kant est une porte à carreaux vitrés qui a des fenètres à côté, si vous êtes au niveau des portes coulissantes la porte sera à votre droite, si vous êtes dans un carrefour la porte sera à votre gauche', 'passer par la porte à carreaux vitrés'),
	(16, 20, 21, 1, 1, 'à gauche des fauteuils bleu et gris, il devrai y avoir une porte', 'regarder la porte qui mène à la cour, retournez-vous, il devrai y avoir une porte'),
	(17, 2, 19, 1, 1, 'si vous êtes au niveau des portes coulissantes il y aura un mur un peu reculé à votre droite, si vous êtes au niveau du carrefour se sera à votre gauche, il y aura 3 portes et la salle "info autonomie" sera la porte qui est à gauche quand on regarde du couloir', 'passer par la porte'),
	(18, 2, 18, 1, 1, 'le cadre educatif a une porte avec un tape code à côté, si vous êtes au niveau des portes coulissantes se sera la 1ère porte à votre droite, si vous êtes au niveau du carrefour se sera la 3ème porte à votre gauche', 'passer par la porte'),
	(19, 3, 24, 1, 1, 'l\'adjoint de direction a une porte avec un cadre "adjoint de direction", si vous êtes au niveau des portes coulissantes se sera la 1ère porte à votre droite, si vous êtes au niveau du croisement des couloirs se sera la 6ème porte à votre gauche', 'passer par la porte'),
	(20, 3, 25, 1, 1, 'la direction a une porte avec un cadre "direction", si vous êtes au niveau des portes coulissantes se sera la2ème porte à votre droite, si vous êtes au niveau du croisement des couloirs se sera la 5ème porte à votre gauche', 'passer par la porte'),
	(21, 3, 26, 1, 1, 'la salle S10 a une porte avec un cadre "10", si vous êtes au niveau des portes coulissantes se sera la 3ème porte à votre droite, si vous êtes au niveau du croisement des couloirs se sera la 4ème porte à votre gauche', 'passer par la porte'),
	(22, 3, 27, 1, 1, 'la salle S14 a une porte avec un cadre "14", si vous êtes au niveau des portes coulissantes se sera la 4ème porte à votre droite, si vous êtes au niveau du croisement des couloirs se sera la 3ème porte à votre gauche', 'passer par la porte'),
	(23, 3, 28, 1, 1, 'la salle S18 a une porte avec un cadre "18", si vous êtes au niveau des portes coulissantes se sera la 5ème porte à votre droite, si vous êtes au niveau du croisement des couloirs se sera la 2ème porte à votre gauche', 'passer par la porte'),
	(24, 3, 29, 1, 1, 'la salle FC-PRO a une porte  près d\'un extincteur de feu avec un cadre "FC-PRO", si vous êtes au niveau des portes coulissantes se sera la 6ème porte à votre droite, si vous êtes au niveau du croisement des couloirs se sera la 1ère porte à votre gauche', 'passer par la porte'),
	(25, 3, 35, 1, 1, 'si vous êtes au niveau des portes coulissantes il y aura un mur un peu reculé à votre gauche, si vous êtes au niveau du croisement de couloir se sera à votre droite, il y aura 3 portes et la salle S8 sera la porte qui est à gauche quand on regarde du couloir', 'passer par la porte'),
	(26, 3, 36, 1, 1, 'si vous êtes au niveau des portes coulissantes il y aura un mur un peu reculé à votre gauche, si vous êtes au niveau du croisement de couloir se sera à votre droite, il y aura 3 portes et la salle RDV sera la porte qui est au milieu quand on regarde du couloir', 'passer par la porte'),
	(27, 3, 37, 1, 1, 'si vous êtes au niveau des portes coulissantes il y aura un mur un peu reculé à votre gauche, si vous êtes au niveau du croisement de couloir se sera à votre droite, il y aura 3 portes et le foyer baby sera la porte qui est à droite quand on regarde du couloir', 'passer par la porte'),
	(28, 3, 38, 1, 1, 'la porte pour aller aux casiers est un porte vitrés qui est à votre droite si vous êtes au niveau du croisement des couloirs ou à votre gauche si vous êtes au niveau des portes coulissantes', 'en regardant les casiers, regarder à gauche, il devrai y avoir une porte'),
	(29, 38, 39, 1, 1, 'en regardant les casiers, retournez-vous, normalement vous devriez voir une porte vitrée marron', 'regarder du côté des fenêtres, regarder à votre gauche, normalement vous verrez une porte vitrée marron'),
	(30, 2, 3, 1, 1, 'avancer dans le couloir jusqu\'à passer devant des portes coulissantes, quand vous passerez devant vous serez dans le couloir principal droite', 'avancer jusqu\'à passer devant des portes coulissantes, quand vous passerez devant vous serez dans le couloir principal gauche'),
	(31, 3, 122, 1, 1, 'avancer jusqu\'à être dans un croisement de couloir, se sera le couloir en face', 'avancer jusqu\'à être dans un croisement de couloir, se sera le couloir en face'),
	(32, 3, 4, 1, 1, 'avancer jusqu\'à être dans un croisement de couloir, se sera le couloir à votre gauche', 'avancer jusqu\'à être dans un croisement de couloir, se sera le couloir à votre droite'),
	(33, 122, 30, 1, 1, 'mettez-vous au niveau du croisement de couloirs, se sera la 1ère porte à droite', 'passer par la porte'),
