	(35, 122, 32, 1, 1, 'mettez-vous au niveau du croisement de couloirs, avancer dans le couloir jusqu\'à la 3ème porte à droite qui a un cadre "26"', 'passer par la porte'),
	(36, 122, 33, 1, 1, 'mettez-vous au niveau du croisement de couloirs, avancer dans le couloir jusqu\'à la 4ème porte à droite avec un cadre "26 bis"', 'passer par la porte'),
	(37, 122, 34, 1, 1, 'tournez-vous comme si vous venez du croisement de couloirs, se sera la dernière porte à droite', 'passer par la porte'),
	(38, 122, 40, 1, 1, 'mettez-vous au niveau du croisement de couloirs, avancer jusqu\'à voir la porte avec un cadre "espace détente"', 'passer par la porte'),
