	(45, 4, 46, 1, 1, 'la porte de la salle se trouve au fond du couloir, il y a juste à avancer', 'passer par la porte'),
	(46, 2, 11, 1, 1, 'la porte de la vie solaire est celle avec un cadre "bureau vie scolaire" si vous êtes au niveau des portes coulissantes se sera la 1ère porte à gauche, si vous êtes au niveau du carrefour se sera la 6ème porte à droite', 'passer par la porte'),
	(47, 44, 45, 1, 1, 'à droite du tableau, il y a une porte qui mène à la salle S34', 'à gauche du tableau, il y a une porte qui mène à la salle S32'),
